insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:9-2-the-environment-and-global-issues:mcq:012bf7d7', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which is the odd one out — NOT a cause of pollution?", "options": ["reciclar", "el tráfico", "la contaminación del aire", "la deforestación"]}'::jsonb, '{"answer": 0, "explain": "reciclar (to recycle) is a solution, not a cause. Traffic, air pollution and deforestation are all problems."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:c6bc87ff', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses the subjunctive after ‘es importante que’?", "options": ["Es importante que reciclemos más", "Es importante que reciclamos más", "Es importante que reciclar más", "Es importante que reciclado más"]}'::jsonb, '{"answer": 0, "explain": "‘es importante que’ triggers the present subjunctive: reciclemos, not the present tense, the infinitive or the past participle."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:bc4d8f7f', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to save'' (rescue)?", "options": ["salvar", "destruir", "contribuir", "advertir"]}'::jsonb, '{"answer": 0, "explain": "salvar = to save/rescue. destruir = to destroy (the opposite!), contribuir = to contribute, advertir = to warn."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:c55e6a73', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''a solution''?", "options": ["una solución", "una intención", "un motivo", "una clave"]}'::jsonb, '{"answer": 0, "explain": "una solución = a solution. una intención = an intention, un motivo = a reason/motive, una clave = a key/crucial point — all abstract nouns you might meet discussing a problem."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:144c390c', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''a citizen''?", "options": ["un ciudadano", "un vecino", "una población", "un país"]}'::jsonb, '{"answer": 0, "explain": "un ciudadano = a citizen. un vecino = a neighbour, una población = a population, un país = a country — all people/place words that are easy to muddle."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:6ad93f51', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''pure''?", "options": ["puro", "profundo", "seco", "eléctrico"]}'::jsonb, '{"answer": 0, "explain": "puro = pure (e.g. aire puro). profundo = deep, seco = dry, eléctrico = electric — other adjectives used to describe nature and energy."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:7ad71836', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''a degree'' (of temperature)?", "options": ["un grado", "una temperatura", "un factor", "un dato"]}'::jsonb, '{"answer": 0, "explain": "un grado = a degree. una temperatura = a temperature (a close relative, but not the same word), un factor = a factor, un dato = a piece of data."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:1a75030f', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''wood'' (the material)?", "options": ["la madera", "la piedra", "el bosque", "el cultivo"]}'::jsonb, '{"answer": 0, "explain": "la madera = wood, the material. la piedra = stone, el bosque = the forest (where wood comes from, but not the material itself), el cultivo = the crop/cultivation."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:1964d3b0', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to warn''?", "options": ["advertir", "conservar", "contribuir", "destruir"]}'::jsonb, '{"answer": 0, "explain": "advertir = to warn (e.g. scientists warn us). conservar = to conserve, contribuir = to contribute, destruir = to destroy."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:f7f5b8d8', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘reciclar’ means ‘to recycle’."}'::jsonb, '{"answer": true, "explain": "reciclar = to recycle, from ‘el reciclaje’ (recycling)."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:01583014', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘la sequía’ means ‘flooding’."}'::jsonb, '{"answer": false, "explain": "la sequía means drought — the opposite of flooding (inundación)."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:7dd8f9e8', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘hay que’ is followed by an infinitive."}'::jsonb, '{"answer": true, "explain": "hay que reciclar / ahorrar / proteger — always an infinitive."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:0a9c7d37', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘se debe’ and ‘no se debe’ mean the same thing."}'::jsonb, '{"answer": false, "explain": "‘se debe’ = one should; ‘no se debe’ = one must not — opposite meanings."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:a24dc0b5', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘el calentamiento global’ means ‘global warming’."}'::jsonb, '{"answer": true, "explain": "calentamiento = warming, global = global."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:457fc56e', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘la pobreza’ means ‘wealth’."}'::jsonb, '{"answer": false, "explain": "la pobreza means poverty, not wealth (la riqueza)."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:2e398d0b', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "Higher: ‘el planeta estará en peligro’ uses the future tense."}'::jsonb, '{"answer": true, "explain": "‘estará’ is the future of estar — the planet WILL BE in danger."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:6ad2ab01', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "Higher: after ‘es importante que’, Spanish uses the subjunctive (e.g. reciclemos)."}'::jsonb, '{"answer": true, "explain": "Impersonal expressions of opinion/necessity trigger the present subjunctive."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:6b44079b', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘el árbol’ means ‘the tree’."}'::jsonb, '{"answer": true, "explain": "el árbol = the tree."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:06f50447', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘pobre’ means ‘rich’."}'::jsonb, '{"answer": false, "explain": "pobre means poor; rich is rico."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:9b26e9ab', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘la paz’ means ‘war’."}'::jsonb, '{"answer": false, "explain": "la paz means peace; war is la guerra."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:tf:da6db875', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'tf', 'tf', 1, '{"question": "‘la pobreza’ and ‘pobre’ are related words meaning ‘poverty’ and ‘poor’."}'::jsonb, '{"answer": true, "explain": "la pobreza (poverty) comes from the same root as pobre (poor)."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:76ab8c79', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about the environment?", "reading": "<p>The key phrase is <span data-say=\"el medio ambiente\">el medio ambiente</span> (the environment). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la contaminación\">la contaminación</span></td><td>pollution</td><td><span data-say=\"el reciclaje\">el reciclaje</span></td><td>recycling</td></tr>\n              <tr><td><span data-say=\"reciclar\">reciclar</span></td><td>to recycle</td><td><span data-say=\"la basura\">la basura</span></td><td>rubbish</td></tr>\n              <tr><td><span data-say=\"la naturaleza\">la naturaleza</span></td><td>nature</td><td><span data-say=\"los recursos naturales\">los recursos naturales</span></td><td>natural resources</td></tr>\n              <tr><td><span data-say=\"la energía\">la energía</span></td><td>energy</td><td><span data-say=\"proteger\">proteger</span></td><td>to protect</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Es importante proteger el medio ambiente y reciclar la basura.\">Es importante proteger el medio ambiente y reciclar la basura.</span> — <em>It is important to protect the environment and recycle rubbish.</em></p>", "question": "What does ‘el medio ambiente’ mean?", "options": ["the environment", "the average weather", "the middle of the city", "a natural resource"]}'::jsonb, '{"answer": 0, "explain": "el medio ambiente = the environment. On its own ‘ambiente’ can mean atmosphere, but this fixed phrase means environment."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:9779d8de', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe environmental problems?", "reading": "<p>Problems facing the planet — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la contaminación del aire\">la contaminación del aire</span></td><td>air pollution</td><td><span data-say=\"el tráfico\">el tráfico</span></td><td>traffic</td></tr>\n              <tr><td><span data-say=\"la deforestación\">la deforestación</span></td><td>deforestation</td><td><span data-say=\"la sequía\">la sequía</span></td><td>drought</td></tr>\n              <tr><td><span data-say=\"el cambio climático\">el cambio climático</span></td><td>climate change</td><td><span data-say=\"el calentamiento global\">el calentamiento global</span></td><td>global warming</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El tráfico causa mucha contaminación del aire en las ciudades.\">El tráfico causa mucha contaminación del aire en las ciudades.</span> — <em>Traffic causes a lot of air pollution in cities.</em></p>", "question": "What is ‘la sequía’?", "options": ["drought", "flooding", "a heatwave", "heavy rain"]}'::jsonb, '{"answer": 0, "explain": "la sequía = drought, a long period without rain. Do not confuse it with inundación (flood) or una ola de calor (heatwave)."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:250aa94d', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "How do I give environmental advice?", "reading": "<p>Reuse the advice structures you already know — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe reciclar\">se debe reciclar</span></td><td>one should recycle</td></tr>\n              <tr><td><span data-say=\"no se debe malgastar agua\">no se debe malgastar agua</span></td><td>one must not waste water</td></tr>\n              <tr><td><span data-say=\"hay que ahorrar energía\">hay que ahorrar energía</span></td><td>you have to save energy</td></tr>\n              <tr><td><span data-say=\"hay que apagar las luces\">hay que apagar las luces</span></td><td>you have to turn off the lights</td></tr>\n              <tr><td><span data-say=\"se debería usar el transporte público\">se debería usar el transporte público</span> <span class=\"tier-h\">H</span></td><td>one should use public transport</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Para proteger el medio ambiente, se debe reciclar y no se debe malgastar el agua.\">Para proteger el medio ambiente, se debe reciclar y no se debe malgastar el agua.</span></p>", "question": "What follows ‘se debe’, ‘hay que’ and ‘se debería’?", "options": ["an infinitive (reciclar, ahorrar…)", "a verb in the preterite past tense", "an adjective that must agree", "a plural noun on its own"]}'::jsonb, '{"answer": 0, "explain": "All three advice structures are followed by an infinitive, never a conjugated verb."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:3a5ab795', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about global issues?", "reading": "<p><span class=\"tier-h\">H</span> At Higher tier you also need wider world problems, not just local ones:</p>\n            <ul>\n              <li><span data-say=\"los problemas globales\">los problemas globales</span> — global problems</li>\n              <li><span data-say=\"la pobreza\">la pobreza</span> — poverty</li>\n              <li><span data-say=\"el hambre\">el hambre</span> — hunger</li>\n              <li><span data-say=\"los países en desarrollo\">los países en desarrollo</span> — developing countries</li>\n            </ul>\n            <p>Example: <span data-say=\"La pobreza y el hambre son problemas globales muy graves.\">La pobreza y el hambre son problemas globales muy graves.</span> — <em>Poverty and hunger are very serious global problems.</em></p>", "question": "What does ‘el hambre’ mean?", "options": ["hunger", "poverty", "a natural disaster", "a global war"]}'::jsonb, '{"answer": 0, "explain": "el hambre = hunger. It uses ‘el’ even though the noun is feminine, because ‘hambre’ starts with a stressed ‘a’ sound."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:99017dbe', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "Higher: predicting the future of the planet", "reading": "<p><span class=\"tier-h\">H</span> Use the simple future (will) to make predictions — take the infinitive and add the future endings:</p>\n            <ul>\n              <li><span data-say=\"el planeta estará en peligro\">el planeta estará en peligro</span> — the planet will be in danger</li>\n              <li><span data-say=\"la situación empeorará\">la situación empeorará</span> — the situation will get worse</li>\n              <li><span data-say=\"habrá menos agua en el futuro\">habrá menos agua en el futuro</span> — there will be less water in the future</li>\n            </ul>\n            <p>Example: <span data-say=\"Si no reciclamos, el planeta estará en peligro.\">Si no reciclamos, el planeta estará en peligro.</span></p>", "question": "‘El planeta estará en peligro’ is which tense?", "options": ["the future (will be)", "the present tense", "a command form", "the preterite past tense"]}'::jsonb, '{"answer": 0, "explain": "‘estará’ is the future tense of estar — ‘will be’."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:e302b4b1', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "Higher: the subjunctive after ‘es importante que’", "reading": "<p><span class=\"tier-h\">H</span> After certain impersonal expressions of opinion or necessity, Spanish uses the <strong>present subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"es importante que reciclemos\">es importante que reciclemos</span> — it is important that we recycle</li>\n              <li><span data-say=\"es necesario que protejamos la naturaleza\">es necesario que protejamos la naturaleza</span> — it is necessary that we protect nature</li>\n            </ul>\n            <p>Compare: <span data-say=\"Reciclamos el papel.\">Reciclamos el papel.</span> (we recycle — a simple statement) with <span data-say=\"Es importante que reciclemos el papel.\">Es importante que reciclemos el papel.</span> (it is important that we recycle — subjunctive after ‘que’).</p>", "question": "Why is it ‘reciclemos’, not ‘reciclamos’, after ‘es importante que’?", "options": ["‘es importante que’ triggers the subjunctive", "‘reciclemos’ is simply the ‘we’ form of the present tense", "the subject has changed from ‘we’ to ‘they’", "it describes a completed action in the past"]}'::jsonb, '{"answer": 0, "explain": "Impersonal expressions like ‘es importante que’ trigger the present subjunctive: reciclemos, not reciclamos."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:ecd26dc8', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "Bigger environmental ideas: cause and effect", "reading": "<p><span class=\"tier-h\">H</span> Wider vocabulary for talking about environmental causes and effects:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"existir\">existir</span></td><td>to exist</td><td><span data-say=\"la tierra\">la tierra</span></td><td>earth / land</td></tr>\n              <tr><td><span data-say=\"el efecto\">el efecto</span></td><td>effect</td><td><span data-say=\"económico\">económico</span></td><td>economic</td></tr>\n              <tr><td><span data-say=\"el dato\">el dato</span></td><td>piece of data</td><td><span data-say=\"la cantidad\">la cantidad</span></td><td>quantity</td></tr>\n              <tr><td><span data-say=\"aumentar\">aumentar</span></td><td>to increase</td><td><span data-say=\"crecer\">crecer</span></td><td>to grow</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En la Tierra existen muchos problemas medioambientales. El efecto invernadero es una causa importante del cambio climático, y tiene consecuencias económicas graves para muchos países. Según los datos científicos, la cantidad de gases en la atmósfera aumenta y el problema crece cada año — por eso el cielo de las grandes ciudades ya no está tan limpio.\">En la Tierra existen muchos problemas medioambientales. El efecto invernadero es una causa importante del cambio climático, y tiene consecuencias económicas graves para muchos países. Según los datos científicos, la cantidad de gases en la atmósfera aumenta y el problema crece cada año — por eso el cielo de las grandes ciudades ya no está tan limpio.</span> — <em>On Earth, many environmental problems exist. The greenhouse effect is an important cause of climate change, and it has serious economic consequences for many countries. According to the scientific data, the amount of gases in the atmosphere is increasing and the problem grows every year — that''s why the sky of big cities is no longer as clean.</em></p>", "question": "According to the text, what does the writer say is increasing every year?", "options": ["the amount of harmful gases in the air", "the number of totally pollution-free countries in the world", "the price families pay for renewable energy every year", "the size of the world''s remaining rainforests and parks"]}'::jsonb, '{"answer": 0, "explain": "‘la cantidad de gases en la atmósfera aumenta … cada año’ = the amount of gases in the atmosphere increases every year. The other options invent facts not in the text."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:fd3ec1f0', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "Global problems: poverty, population and solutions", "reading": "<p><span class=\"tier-h\">H</span> Vocabulary for discussing world problems and who is trying to solve them:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la población\">la población</span></td><td>population</td><td><span data-say=\"pobre\">pobre</span></td><td>poor</td></tr>\n              <tr><td><span data-say=\"sufrir\">sufrir</span></td><td>to suffer</td><td><span data-say=\"la diferencia\">la diferencia</span></td><td>difference</td></tr>\n              <tr><td><span data-say=\"la organización\">la organización</span></td><td>organisation</td><td><span data-say=\"la paz\">la paz</span></td><td>peace</td></tr>\n              <tr><td><span data-say=\"la fuente\">la fuente</span></td><td>source</td><td><span data-say=\"desaparecer\">desaparecer</span></td><td>to disappear</td></tr>\n            </table>\n            <p>Example: <span data-say=\"La población mundial sigue creciendo, y muchas personas pobres sufren de hambre y falta de agua potable. Hay una gran diferencia entre los países ricos y los países en desarrollo. Organizaciones como la ONU trabajan por la paz y buscan fuentes de energía limpia para que los bosques no desaparezcan. El peor problema es que muchos gobiernos no actúan lo suficiente.\">La población mundial sigue creciendo, y muchas personas pobres sufren de hambre y falta de agua potable. Hay una gran diferencia entre los países ricos y los países en desarrollo. Organizaciones como la ONU trabajan por la paz y buscan fuentes de energía limpia para que los bosques no desaparezcan. El peor problema es que muchos gobiernos no actúan lo suficiente.</span> — <em>The world population keeps growing, and many poor people suffer from hunger and a lack of drinking water. There is a big difference between rich countries and developing countries. Organisations like the UN work for peace and look for sources of clean energy so that forests don''t disappear. The worst problem is that many governments don''t act enough.</em></p>", "question": "According to the text, what do organisations like the UN look for?", "options": ["clean sources of energy", "new countries to develop and industrialise", "cheaper food for poor families everywhere", "bigger cities to house a growing population"]}'::jsonb, '{"answer": 0, "explain": "‘buscan fuentes de energía limpia’ = they look for clean sources of energy. The other options are not stated in the text."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:learn:1cd9f073', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'learn', 'mcq', 1, '{"readingTitle": "Nature under threat: trees, forests and deforestation", "reading": "<p><span class=\"tier-h\">H</span> More vocabulary for talking about nature and deforestation:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el árbol\">el árbol</span></td><td>tree</td><td><span data-say=\"cortar\">cortar</span></td><td>to cut</td></tr>\n              <tr><td><span data-say=\"utilizar\">utilizar</span></td><td>to use</td><td><span data-say=\"el estado\">el estado</span></td><td>state / condition</td></tr>\n              <tr><td><span data-say=\"la época\">la época</span></td><td>era / time period</td><td><span data-say=\"la duda\">la duda</span></td><td>doubt</td></tr>\n              <tr><td><span data-say=\"apenas\">apenas</span></td><td>hardly / barely</td><td><span data-say=\"igual\">igual</span></td><td>equal / the same</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cada año se cortan miles de árboles para utilizar la madera o crear más tierras de cultivo. En esta época de cambio climático, no hay duda de que el estado de los bosques del mundo está empeorando: en algunas zonas apenas quedan árboles, y esto no es igual en todos los países — algunos protegen sus bosques mucho mejor que otros.\">Cada año se cortan miles de árboles para utilizar la madera o crear más tierras de cultivo. En esta época de cambio climático, no hay duda de que el estado de los bosques del mundo está empeorando: en algunas zonas apenas quedan árboles, y esto no es igual en todos los países — algunos protegen sus bosques mucho mejor que otros.</span> — <em>Every year thousands of trees are cut down to use the wood or create more farmland. In this era of climate change, there is no doubt that the state of the world''s forests is getting worse: in some areas hardly any trees are left, and this isn''t the same in every country — some protect their forests much better than others.</em></p>", "question": "According to the text, what has happened in some areas because of deforestation?", "options": ["hardly any trees are left", "every country now protects its forests equally well", "the climate has completely stopped changing", "more farmland has been turned back into forest"]}'::jsonb, '{"answer": 0, "explain": "‘apenas quedan árboles’ = hardly any trees are left. The other options invent facts not in the text."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:misc:8ba303d1', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> <span data-say=\"Se debe malgastar el agua.\">Se debe malgastar el agua.</span></p><p><strong>✅ The correct idea:</strong> <span data-say=\"No se debe malgastar el agua.\">No se debe malgastar el agua.</span></p>", "question": "What does ‘malgastar’ mean?", "options": ["to waste", "to save", "to recycle", "to protect"]}'::jsonb, '{"answer": 0, "explain": "malgastar = to waste. It is often confused with ‘ahorrar’ (to save) because both appear beside environment vocabulary."}'::jsonb),
